import { initTRPC } from '@trpc/server';
import * as trpcExpress from '@trpc/server/adapters/express';
import express from 'express';
import cors from 'cors';
import fs from 'fs';

const t = initTRPC.create();

const appRouter = t.router({
  countdown: t.procedure.subscription(async function* () {
    fs.appendFileSync('server.log', 'countdown called\n');
    for (let i = 5; i > 0; i--) {
      fs.appendFileSync('server.log', `yielding ${i}\n`);
      await new Promise((resolve) => setTimeout(resolve, 100));
      yield i;
    }
  }),
});

export type AppRouter = typeof appRouter;

const app = express();
app.use(cors());

app.use((req, res, next) => {
  fs.appendFileSync('server.log', `${req.method} ${req.url}\n`);
  next();
});

app.use(
  '/trpc',
  trpcExpress.createExpressMiddleware({
    router: appRouter,
  })
);

const server = app.listen(3000, () => {
  fs.appendFileSync('server.log', 'Server started on port 3000\n');
});

export { server };

